mapper.select:
select entrust_test_type
from test_entrusted_info
where id = #{id}

update.foreach:
update test_entrusted_sample_checkitem_rel

    standard_id = #{item.standardId},
    times = #{item.times}

where entrust_id = #{item.entrustId} and check_item_id = #{item.checkItemId}

mapper.select:
SELECT t1.contacts
FROM test_customer as t1
         LEFT JOIN test_company as t2 ON t1.company_id = t2.company_id
WHERE t2.company_name = #{companyName}
  and type = #{type}
  and t1.contacts = #{contacts}

      and t1.phone = #{contactWay}

LIMIT 1

SELECT sample_id
FROM test_entrusted_sample_details_rel
WHERE entrustment_id = #{entrustmentId}

SELECT sum(price)
FROM test_entrusted_payment_record_info
WHERE entrustment_id = #{entrustmentId}

SELECT sample_id
FROM test_entrusted_sample_details_rel
where entrustment_id = #{entrustmentId}
